                                    </span>
                                    Call to Order
                                </a>
                                <a 
                                    href="https://wa.me/919798881368" 
                                    target="_blank" 
                                    rel="noopener noreferrer" 
                                    className="flex-1 bg-[#25D366] text-white font-bold py-3.5 px-6 rounded-xl hover:bg-[#20bd5a] transition shadow-lg flex items-center justify-center group"
                                >
                                    <span className="bg-white/20 p-1.5 rounded-full mr-3 group-hover:rotate-12 transition-transform">
                                        <i className="fab fa-whatsapp text-lg"></i>
                                    </span>
                                    WhatsApp
                                </a>
                            </div>
                            <div className="mt-6 pt-6 border-t border-gray-100 flex items-start gap-3">
                                <i className="fas fa-info-circle text-gray-400 mt-0.5"></i>
                                <p className="text-xs text-gray-400 leading-snug">
                                    Product availability is subject to stock. For Schedule H and H1 drugs, a valid prescription from a registered medical practitioner is mandatory.
                                </p>
                            </div>
                         </div>
                    </div>
                </div>
            )}
        </section>
    );
};

