            question: "Do you offer home delivery?",
            answer: "Currently, we do not offer home delivery services. We request our customers to visit the store personally for their requirements. You can, however, call or WhatsApp us to confirm product availability before your visit."
        },
        {
            question: "What payment methods do you accept?",
            answer: "We accept Cash and all major UPI apps including PhonePe, Google Pay, and Paytm. We are currently working on enabling credit/debit card swipe machines for your convenience."
        },
        {
            question: "Can I return medicines if I don't need them?",
            answer: "Medicines can be returned within 3 days of purchase if they are unopened, in their original condition, and accompanied by the bill. Please note that refrigerated items (like insulin) and cut strips are non-returnable."
        }
    ];

    const toggleFAQ = (index: number) => {
        setOpenIndex(openIndex === index ? null : index);
    };

    return (
        <section id="faq" className="py-16 bg-gray-50 scroll-mt-24">
            <div className="container mx-auto px-4 max-w-4xl">
                <div className="text-center mb-12 reveal">
                    <span className="inline-block py-1 px-3 rounded-full bg-medical-100 text-medical-800 text-sm font-semibold mb-3">
                        <i className="fas fa-question-circle mr-1"></i> Help Center
                    </span>
                    <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4">Frequently Asked Questions</h2>
                    <p className="text-gray-600">Find answers to common questions about our services, timings, and policies.</p>
                </div>

                <div className="space-y-4">
                    {faqs.map((faq, index) => (
                        <div 
                            key={index} 
                            className={`reveal reveal-delay-${(index % 3 + 1) * 100} bg-white rounded-2xl border border-gray-100 overflow-hidden transition-all duration-300 ${openIndex === index ? 'shadow-lg ring-1 ring-medical-200' : 'shadow-sm hover:shadow-md'}`}
                        >
                            <button
                                onClick={() => toggleFAQ(index)}
                                className="w-full flex items-center justify-between p-5 text-left focus:outline-none group"
                                aria-expanded={openIndex === index}
                            >
                                <span className={`font-bold text-lg transition-colors duration-300 ${openIndex === index ? 'text-medical-600' : 'text-gray-800 group-hover:text-medical-600'}`}>
                                    {faq.question}
                                </span>
                                <span className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 ${openIndex === index ? 'bg-medical-100 text-medical-600 rotate-180' : 'bg-gray-50 text-gray-400 group-hover:bg-medical-50'}`}>
                                    <i className="fas fa-chevron-down text-sm"></i>
                                </span>
                            </button>
                            <div 
                                className={`transition-all duration-500 ease-in-out overflow-hidden ${openIndex === index ? 'max-h-48 opacity-100' : 'max-h-0 opacity-0'}`}
                            >
                                <div className="p-5 pt-0 text-gray-600 border-t border-gray-50 leading-relaxed bg-gradient-to-b from-white to-gray-50/50">
                                    {faq.answer}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </section>
    );
};

