const Products: React.FC = () => {
    const [searchQuery, setSearchQuery] = useState('');
    const [displayedProducts, setDisplayedProducts] = useState<Product[]>(productList);
    const [isSearching, setIsSearching] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);
    const [isAiResult, setIsAiResult] = useState(false);
    const [isFocused, setIsFocused] = useState(false);

    // Quick View State
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

    // Review State
    const [reviews, setReviews] = useState<Review[]>(initialReviews);
    const [newReview, setNewReview] = useState({ userName: '', rating: 5, comment: '' });
    const [isReviewSubmitting, setIsReviewSubmitting] = useState(false);

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsFocused(false);

        if (!searchQuery.trim()) {
            setDisplayedProducts(productList);
            setHasSearched(false);
            setIsAiResult(false);
            return;
        }

        setHasSearched(true);
        setIsSearching(true);
        setIsAiResult(false);

        const lowerQuery = searchQuery.toLowerCase();
        const localResults = productList.filter(p => 
            p.name.toLowerCase().includes(lowerQuery) || 
            p.description.toLowerCase().includes(lowerQuery)
        );

        if (localResults.length > 0) {
            setDisplayedProducts(localResults);
            setIsSearching(false);
        } else {
            const aiResults = await searchProducts(searchQuery);
            setDisplayedProducts(aiResults);
            setIsAiResult(true);
            setIsSearching(false);
        }
    };

    const clearSearch = () => {
        setSearchQuery('');
        setDisplayedProducts(productList);
        setHasSearched(false);
        setIsAiResult(false);
        setIsSearching(false);
        document.getElementById('product-search-input')?.focus();
    };

    // Quick View Handlers
    const openQuickView = (product: Product) => {
        setSelectedProduct(product);
        document.body.style.overflow = 'hidden';
        // Reset review form when opening new product
        setNewReview({ userName: '', rating: 5, comment: '' });
    };

    const closeQuickView = () => {
        setSelectedProduct(null);
        document.body.style.overflow = 'unset';
    };

    // Handle Review Submission
    const handleReviewSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedProduct) return;
        if (!newReview.userName.trim() || !newReview.comment.trim()) return;

        setIsReviewSubmitting(true);

        // Simulate network delay
        setTimeout(() => {
            const review: Review = {
                id: Date.now().toString(),
                productId: selectedProduct.id,
                userName: newReview.userName,
                rating: newReview.rating,
                comment: newReview.comment,
                date: new Date().toISOString().split('T')[0]
            };

            setReviews(prev => [review, ...prev]);
            setNewReview({ userName: '', rating: 5, comment: '' });
            setIsReviewSubmitting(false);
        }, 800);
    };

    // Filter reviews for selected product
    const productReviews = selectedProduct 
        ? reviews.filter(r => r.productId === selectedProduct.id) 
        : [];

    // Calculate average rating
    const averageRating = productReviews.length > 0 
        ? (productReviews.reduce((sum, r) => sum + r.rating, 0) / productReviews.length).toFixed(1)
