                         </div>

                         {/* Right: Details & Reviews (Scrollable) */}
                         <div className="w-full md:w-3/5 overflow-y-auto max-h-[90vh]">
                             <div className="p-8 md:p-10">
                                <span className="inline-block px-3 py-1 bg-medical-100 text-medical-700 rounded-full text-xs font-bold tracking-wide uppercase mb-4 w-fit">
                                    Pharmaceutical Product
                                </span>
                                <div className="flex justify-between items-start">
                                    <h2 id="modal-title" className="text-3xl font-bold text-gray-900 mb-2">{selectedProduct.name}</h2>
                                    <div className="flex items-center bg-yellow-50 px-3 py-1 rounded-lg border border-yellow-100">
                                        <span className="text-xl font-bold text-gray-800 mr-1">{averageRating}</span>
                                        <div className="text-yellow-400 text-sm">
                                            <i className="fas fa-star"></i>
                                        </div>
                                    </div>
                                </div>
                                <div className="w-16 h-1.5 bg-gradient-to-r from-medical-500 to-medical-300 rounded-full mb-6 mt-2"></div>

                                <div className="prose prose-sm text-gray-600 text-lg leading-relaxed mb-8">
                                    <p>{selectedProduct.description}</p>
                                </div>

                                {/* Reviews Section */}
                                <div className="border-t border-gray-100 pt-8 mt-8">
                                    <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center">
                                        <i className="far fa-comments mr-2 text-medical-600"></i> Customer Reviews
                                    </h3>

                                    {/* Add Review Form */}
                                    <form onSubmit={handleReviewSubmit} className="bg-gray-50 p-5 rounded-2xl mb-8 border border-gray-100">
                                        <h4 className="text-sm font-bold text-gray-700 mb-3">Write a Review</h4>
                                        <div className="mb-3">
                                            <div className="flex gap-1 mb-2">
                                                {[1, 2, 3, 4, 5].map((star) => (
                                                    <button 
                                                        key={star}
                                                        type="button"
                                                        onClick={() => setNewReview({...newReview, rating: star})}
                                                        className={`text-xl focus:outline-none transition-transform hover:scale-110 ${star <= newReview.rating ? 'text-yellow-400' : 'text-gray-300'}`}
                                                    >
                                                        <i className="fas fa-star"></i>
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                        <div className="mb-3">
                                            <input 
                                                type="text" 
                                                placeholder="Your Name" 
                                                className="w-full px-4 py-2 rounded-lg border border-gray-200 focus:outline-none focus:border-medical-500 text-sm"
