                                        </div>
                                        <div className="mb-3">
                                            <textarea 
                                                placeholder="Share your experience..." 
                                                className="w-full px-4 py-2 rounded-lg border border-gray-200 focus:outline-none focus:border-medical-500 text-sm resize-none h-20"
                                                value={newReview.comment}
                                                onChange={(e) => setNewReview({...newReview, comment: e.target.value})}
                                                required
                                            ></textarea>
                                        </div>
                                        <button 
                                            type="submit" 
                                            disabled={isReviewSubmitting}
                                            className="bg-medical-600 text-white px-5 py-2 rounded-lg text-sm font-bold hover:bg-medical-700 transition shadow-sm disabled:opacity-50"
                                        >
                                            {isReviewSubmitting ? 'Submitting...' : 'Post Review'}
