import React, { useState, useRef, useEffect } from 'react';
import { getGeminiResponse } from '../services/geminiService';
import { ChatMessage } from '../types';

const AIChat: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [inputValue, setInputValue] = useState('');
    const [selectedImage, setSelectedImage] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const defaultMessage: ChatMessage = {
        id: 'welcome',
        text: "Hello! 👋 I'm your AI Pharmacist assistant. \n\nAsk me about: \n💊 Medicine uses \n🤒 Common symptoms \n🌿 Home remedies \n📷 Upload a photo of a medicine or prescription for help! \n\nNote: I am an AI, not a doctor. Please consult a professional for serious advice.",
        isUser: false,
        timestamp: Date.now()
    };

    // Load history from local storage on mount
    useEffect(() => {
        const savedHistory = localStorage.getItem('chat_history');
        if (savedHistory) {
            try {
                const parsed = JSON.parse(savedHistory);
                if (Array.isArray(parsed) && parsed.length > 0) {
                    setMessages(parsed);
                } else {
                    setMessages([defaultMessage]);
                }
            } catch (e) {
                console.error("Failed to parse chat history", e);
                setMessages([defaultMessage]);
            }
        } else {
            setMessages([defaultMessage]);
        }
    }, []);

    // Save history to local storage whenever messages change
    useEffect(() => {
        if (messages.length > 0) {
            localStorage.setItem('chat_history', JSON.stringify(messages));
        }
    }, [messages]);

    // Listen for 'ask-ai' custom events from other components
    useEffect(() => {
        const handleAskAI = (e: any) => {
            const { productName, description } = e.detail;
            const query = `Can you explain what ${productName} is used for and provide some health tips? \n\nDescription context: ${description}`;

            setIsOpen(true);

            // Trigger the AI request
            handleExternalQuery(query);
        };

        window.addEventListener('ask-ai', handleAskAI);
        return () => window.removeEventListener('ask-ai', handleAskAI);
    }, []);

    const toggleChat = () => setIsOpen(!isOpen);

    const clearHistory = () => {
        if (window.confirm("Are you sure you want to clear your chat history?")) {
            setMessages([defaultMessage]);
            localStorage.removeItem('chat_history');
        }
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isOpen]);

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onloadend = () => {
                setSelectedImage(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    const removeImage = () => {
        setSelectedImage(null);
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const handleExternalQuery = async (text: string) => {
        const newMessage: ChatMessage = {
            id: Date.now().toString(),
            text: text,
            isUser: true,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, newMessage]);
        setIsLoading(true);

        const aiResponseText = await getGeminiResponse(text);

        const aiMessage: ChatMessage = {
            id: (Date.now() + 1).toString(),
            text: aiResponseText,
            isUser: false,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, aiMessage]);
        setIsLoading(false);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!inputValue.trim() && !selectedImage) return;

        const userText = inputValue.trim();
        const userImage = selectedImage;

        const newMessage: ChatMessage = {
            id: Date.now().toString(),
            text: userText,
            image: userImage || undefined,
            isUser: true,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, newMessage]);
        setInputValue('');
        setSelectedImage(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
        setIsLoading(true);

        const aiResponseText = await getGeminiResponse(userText, userImage || undefined);

        const aiMessage: ChatMessage = {
            id: (Date.now() + 1).toString(),
            text: aiResponseText,
            isUser: false,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, aiMessage]);
        setIsLoading(false);
    };

    return (
        <>
            {/* FAB */}
            <button 
                onClick={toggleChat}
                className="fixed bottom-6 right-6 z-[90] bg-gradient-to-r from-medical-600 to-medical-500 hover:from-medical-700 hover:to-medical-600 text-white p-4 rounded-full shadow-2xl transition transform hover:scale-110 group animate-pulse"
            >
                <span className="absolute -top-1 -right-1 flex h-4 w-4">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-yellow-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-4 w-4 bg-yellow-500"></span>
                </span>
                <i className={`fas ${isOpen ? 'fa-times' : 'fa-robot'} text-2xl group-hover:rotate-12 transition duration-300`}></i>
                <span className="absolute right-full mr-3 top-1/2 -translate-y-1/2 bg-gray-900 text-white px-3 py-1 rounded-lg text-sm font-bold whitespace-nowrap opacity-0 group-hover:opacity-100 transition duration-300 pointer-events-none shadow-lg">
                    ✨ AI Pharmacist
                </span>
            </button>

            {/* Modal */}
            <div 
                className={`fixed inset-0 z-[100] flex items-end sm:items-center justify-center px-0 sm:px-4 backdrop-blur-sm bg-black/50 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
                onClick={(e) => e.target === e.currentTarget && toggleChat()}
            >
                <div 
                    className={`bg-white w-full sm:max-w-md h-[85vh] sm:h-[600px] sm:rounded-3xl rounded-t-3xl shadow-2xl flex flex-col transform transition-transform duration-300 ${isOpen ? 'translate-y-0 scale-100' : 'translate-y-full sm:translate-y-0 scale-95'}`}
                >
                    {/* Header */}
                    <div className="bg-gradient-to-r from-medical-600 to-medical-500 p-4 flex items-center justify-between sm:rounded-t-3xl rounded-t-3xl">
                        <div className="flex items-center gap-3">
