                                <p className="text-medical-100 text-xs flex items-center">
                                    <span className="w-2 h-2 bg-green-400 rounded-full mr-1 animate-pulse"></span> Online
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <button 
                                onClick={clearHistory}
                                className="text-white/80 hover:text-white hover:bg-white/10 p-2 rounded-full transition"
                                title="Clear History"
                            >
                                <i className="fas fa-trash-alt text-sm"></i>
                            </button>
                            <button onClick={toggleChat} className="text-white/80 hover:text-white transition p-2 hover:bg-white/10 rounded-full">
                                <i className="fas fa-times text-xl"></i>
                            </button>
                        </div>
                    </div>

                    {/* Chat Area */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 scroll-smooth">
                        {messages.map((msg) => (
                            <div key={msg.id} className={`flex items-start gap-3 animate-slide-up ${msg.isUser ? 'flex-row-reverse' : ''}`}>
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.isUser ? 'bg-gray-200' : 'bg-medical-100'}`}>
                                    <i className={`fas ${msg.isUser ? 'fa-user text-gray-600' : 'fa-robot text-medical-600'} text-sm`}></i>
                                </div>
                                <div className={`flex flex-col ${msg.isUser ? 'items-end' : 'items-start'} max-w-[80%]`}>
                                    <div className={`${msg.isUser ? 'bg-medical-600 text-white rounded-tr-none' : 'bg-white text-gray-700 rounded-tl-none border border-gray-100'} p-3 rounded-2xl shadow-sm text-sm whitespace-pre-wrap`}>
                                        {msg.image && (
                                            <img 
                                                src={msg.image} 
                                                alt="User upload" 
                                                className="rounded-lg mb-2 max-h-48 object-cover border border-white/20"
                                            />
                                        )}
                                        {msg.text}
                                    </div>
                                    <span className="text-[10px] text-gray-400 mt-1 px-1">
                                        {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                    </span>
                                </div>
                            </div>
                        ))}
                        {isLoading && (
                            <div className="flex items-start gap-3 animate-slide-up">
                                <div className="w-8 h-8 rounded-full bg-medical-100 flex items-center justify-center flex-shrink-0">
                                    <i className="fas fa-robot text-medical-600 text-sm"></i>
                                </div>
                                <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm border border-gray-100 flex gap-1">
                                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-typing" style={{ animationDelay: '-0.32s' }}></div>
                                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-typing" style={{ animationDelay: '-0.16s' }}></div>
                                    <div className="w-2 h-2 bg-gray-400 rounded-full animate-typing"></div>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Input Area */}
                    <div className="p-4 bg-white border-t border-gray-100 relative">
                        {/* Image Preview */}
                        {selectedImage && (
                            <div className="absolute bottom-full left-4 mb-2 bg-white p-2 rounded-xl shadow-lg border border-gray-100 animate-slide-up">
                                <div className="relative">
                                    <img src={selectedImage} alt="Preview" className="h-20 w-20 object-cover rounded-lg" />
                                    <button 
                                        onClick={removeImage}
                                        className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs shadow-sm hover:bg-red-600 transition"
                                    >
                                        <i className="fas fa-times"></i>
                                    </button>
                                </div>
                            </div>
                        )}

                        <form onSubmit={handleSubmit} className="flex gap-2 relative items-end">
                            <input 
                                type="file" 
                                ref={fileInputRef}
                                accept="image/*"
                                className="hidden"
                                onChange={handleFileSelect}
                            />

                            <button 
                                type="button"
                                onClick={triggerFileInput}
                                className={`w-10 h-10 rounded-full flex items-center justify-center transition mb-1 ${selectedImage ? 'bg-medical-100 text-medical-600' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
                                title="Attach Image"
                            >
                                <i className="fas fa-camera"></i>
                            </button>

                            <div className="flex-1 bg-gray-100 border-0 rounded-3xl px-4 py-2 focus-within:ring-2 focus-within:ring-medical-500 focus-within:bg-white transition">
                                <textarea 
                                    value={inputValue}
                                    onChange={(e) => setInputValue(e.target.value)}
                                    placeholder={selectedImage ? "Add a caption..." : "Type question or upload photo..."}
                                    className="w-full bg-transparent border-none focus:ring-0 text-sm resize-none max-h-24 py-2 outline-none"
                                    rows={1}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter' && !e.shiftKey) {
                                            e.preventDefault();
                                            handleSubmit(e);
                                        }
                                    }}
                                />
                            </div>

                            <button 
                                type="submit" 
                                disabled={isLoading || (!inputValue.trim() && !selectedImage)}
                                className="bg-medical-600 hover:bg-medical-700 text-white w-10 h-10 rounded-full flex items-center justify-center transition shadow-md disabled:opacity-50 disabled:cursor-not-allowed mb-1 flex-shrink-0"
                            >
                                <i className="fas fa-paper-plane"></i>
                            </button>
                        </form>
                        <p className="text-center text-[10px] text-gray-400 mt-2">Powered by Gemini AI ✨</p>
                    </div>
                </div>
            </div>
        </>
    );
};

