                                    aria-expanded={isOpen}
                                >
                                    <span className={`font-bold text-lg transition-colors duration-300 ${isOpen ? 'text-medical-600' : 'text-gray-800 group-hover:text-medical-600'}`}>
                                        {faq.question}
                                    </span>
                                    <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 ${isOpen ? 'bg-medical-100 text-medical-600 rotate-180' : 'bg-gray-50 text-gray-400 group-hover:bg-medical-50'}`}>
                                        <i className="fas fa-chevron-down text-sm"></i>
                                    </div>
                                </button>
                                <div 
                                    className={`grid transition-[grid-template-rows] duration-500 ease-in-out ${isOpen ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}
                                >
                                    <div className="overflow-hidden min-h-0">
                                        <div className="p-5 pt-0 text-gray-600 border-t border-gray-50 leading-relaxed bg-gradient-to-b from-white to-gray-50/50">
                                            {faq.answer}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </section>
    );
};

