const Products: React.FC = () => {
    const [searchQuery, setSearchQuery] = useState('');
    const [displayedProducts, setDisplayedProducts] = useState<Product[]>(productList);
    const [isSearching, setIsSearching] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);
    const [isAiResult, setIsAiResult] = useState(false);
    const [isFocused, setIsFocused] = useState(false);

    // Quick View State
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsFocused(false);

        if (!searchQuery.trim()) {
            setDisplayedProducts(productList);
            setHasSearched(false);
            setIsAiResult(false);
            return;
        }

        setHasSearched(true);
        setIsSearching(true);
        setIsAiResult(false);

        const lowerQuery = searchQuery.toLowerCase();
        const localResults = productList.filter(p => 
            p.name.toLowerCase().includes(lowerQuery) || 
            p.description.toLowerCase().includes(lowerQuery)
        );

        if (localResults.length > 0) {
            setDisplayedProducts(localResults);
            setIsSearching(false);
        } else {
            const aiResults = await searchProducts(searchQuery);
            setDisplayedProducts(aiResults);
            setIsAiResult(true);
            setIsSearching(false);
        }
    };

    const clearSearch = () => {
        setSearchQuery('');
        setDisplayedProducts(productList);
        setHasSearched(false);
        setIsAiResult(false);
        setIsSearching(false);
        document.getElementById('product-search-input')?.focus();
    };

    // Quick View Handlers
    const openQuickView = (product: Product) => {
        setSelectedProduct(product);
        document.body.style.overflow = 'hidden';
    };

    const closeQuickView = () => {
        setSelectedProduct(null);
        document.body.style.overflow = 'unset';
    };

    const askAI = (product: Product, e: React.MouseEvent) => {
        e.stopPropagation(); // Prevent opening quick view if clicked from card overlay
        // Dispatch custom event for AIChat component
        const event = new CustomEvent('ask-ai', { 
            detail: { productName: product.name, description: product.description } 
        });
        window.dispatchEvent(event);
        closeQuickView(); // Close modal if open
    };

    useEffect(() => {
        const handleEsc = (e: KeyboardEvent) => {
            if (e.key === 'Escape') closeQuickView();
        };
        window.addEventListener('keydown', handleEsc);
        return () => window.removeEventListener('keydown', handleEsc);
    }, []);

    return (
        <section id="products" className="bg-medical-50 scroll-mt-24 min-h-[800px] transition-all duration-500 relative" aria-label="Products Section">

            {/* Search Focus Backdrop - Always visible when focused to emphasize input */}
            {isFocused && (
                <div 
                    className="fixed inset-0 bg-black/50 z-[55] backdrop-blur-sm transition-opacity duration-300 animate-fade-in" 
                    onClick={() => setIsFocused(false)}
                    aria-hidden="true"
                ></div>
            )}

            <div className="container mx-auto px-4 py-16">

                {/* No Delivery Notice Banner */}
                <div className="bg-orange-50 border-l-4 border-orange-500 p-4 mb-8 rounded-r-lg shadow-sm reveal flex items-start md:items-center animate-fade-in">
                    <div className="flex-shrink-0 text-orange-500">
                        <i className="fas fa-store-slash text-2xl"></i>
                    </div>
                    <div className="ml-4">
                        <h3 className="text-lg font-bold text-orange-800">Store Pickup Only</h3>
                        <p className="text-orange-700 text-sm">
                            We currently <span className="font-bold">do not offer home delivery</span>. Please visit our store in Hanwara to purchase medicines. 
                            You can check availability via WhatsApp before visiting.
                        </p>
                    </div>
                </div>

                <div className={`transition-all duration-700 ease-in-out flex flex-col items-center ${hasSearched ? 'mt-0 mb-8' : 'mt-10 mb-20'}`}>
