                            : 'relative'}
                    `}>
                        <form onSubmit={handleSearch} className="relative group w-full" role="search">
                            <label htmlFor="product-search-input" className="sr-only">Search medicines, products, or symptoms</label>
                            <div className={`absolute inset-0 bg-gradient-to-r from-medical-400 to-blue-400 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-300 ${isSearching ? 'animate-pulse' : ''} ${isFocused ? 'hidden md:block' : ''}`}></div>
                            <input 
                                id="product-search-input"
                                type="search" 
                                value={searchQuery}
                                onFocus={() => setIsFocused(true)}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                placeholder="Search medicines, products, or symptoms..." 
                                className="w-full bg-white border-2 border-gray-100 text-gray-800 text-lg rounded-full py-4 pl-6 pr-24 shadow-lg focus:outline-none focus:border-medical-500 focus:shadow-xl transition-all duration-300 relative z-10"
                                aria-label="Search medicines, products, or symptoms"
                            />

                            {searchQuery && (
                                <button
                                    type="button"
                                    onClick={clearSearch}
                                    className="absolute right-14 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 p-2 z-20 transition-colors"
                                    aria-label="Clear search"
                                >
                                    <i className="fas fa-times"></i>
                                </button>
                            )}

                            <button 
                                type="submit"
                                className="absolute right-3 top-1/2 -translate-y-1/2 bg-medical-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-medical-700 transition z-20 shadow-md group-hover:scale-110"
                                aria-label={isSearching ? "Searching..." : "Search"}
                                disabled={isSearching}
                            >
                                {isSearching ? (
                                    <i className="fas fa-spinner fa-spin" aria-hidden="true"></i>
                                ) : (
                                    <i className="fas fa-search" aria-hidden="true"></i>
                                )}
                            </button>
                        </form>
                        {isAiResult && !isSearching && (
                            <div className="text-center mt-2 text-xs text-gray-500 flex items-center justify-center gap-1 animate-slide-up" role="status">
                                <i className="fab fa-google text-medical-600" aria-hidden="true"></i>
                                <span>Results found via Google AI</span>
                            </div>
                        )}

                        {isFocused && (
                            <button 
                                onClick={() => setIsFocused(false)}
                                className="md:hidden absolute -bottom-10 left-1/2 transform -translate-x-1/2 text-gray-500 text-sm font-medium bg-white/80 px-4 py-1 rounded-full shadow-sm"
                                aria-label="Close search mode"
                            >
                                <i className="fas fa-times-circle mr-1" aria-hidden="true"></i> Close
                            </button>
                        )}
                    </div>
                </div>

                <div 
                    className={`grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 transition-all duration-700 ${isSearching ? 'opacity-50 blur-sm' : 'opacity-100 blur-0'}`}
                    role="region"
                    aria-label="Search Results"
                    aria-live="polite"
                >
                    {displayedProducts.length > 0 ? (
                        displayedProducts.map((product) => (
                            <div key={product.id} className={`reveal ${product.delay || ''} bg-white rounded-lg shadow-md hover-lift-smooth overflow-hidden flex flex-col h-full group animate-slide-up`}>
                                <div 
                                    className="overflow-hidden h-48 p-4 relative cursor-pointer bg-white group-hover:bg-gray-50 transition-colors duration-300"
                                    onClick={() => openQuickView(product)}
                                >
                                    <img 
                                        src={product.image} 
                                        alt={product.name} 
                                        loading="lazy"
                                        className="w-full h-full object-contain transform transition-transform duration-700 ease-in-out group-hover:scale-110 group-hover:-translate-y-2" 
                                    />
                                    {isAiResult && (
                                        <span className="absolute top-2 right-2 bg-blue-100 text-blue-800 text-xs font-bold px-2 py-1 rounded-full animate-scale-up">
                                            AI Found
                                        </span>
                                    )}

                                    {/* Hover Overlay with Buttons - Only Quick View here */}
                                    <div className="absolute inset-0 bg-black/5 group-hover:bg-black/10 transition-colors duration-300 flex items-center justify-center opacity-0 group-hover:opacity-100">
                                        <button className="bg-white text-gray-800 px-4 py-2 rounded-full transform translate-y-4 group-hover:translate-y-0 transition-all duration-300 shadow-lg hover:bg-medical-600 hover:text-white font-medium text-sm flex items-center w-36 justify-center">
                                            <i className="fas fa-eye mr-2"></i> Quick View
                                        </button>
                                    </div>
                                </div>
                                <div className="p-5 flex flex-col flex-grow">
                                    <div className="flex justify-between items-start mb-3">
                                        <h3 className="font-bold text-lg text-gray-800 group-hover:text-medical-600 transition-colors">{product.name}</h3>
                                    </div>
                                    <p className="text-sm text-gray-600 mb-4 line-clamp-3">{product.description}</p>
                                    <div className="mt-auto pt-2 border-t border-gray-100 flex items-center justify-center">
                                        <button 
                                            onClick={() => openQuickView(product)}
                                            className="w-full text-center text-medical-600 font-semibold text-sm hover:underline py-2"
                                        >
                                            View Details
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))
                    ) : (
                        <div className="col-span-full text-center py-12 animate-fade-in" role="status">
                            <div className="text-gray-400 mb-4">
                                <i className="fas fa-search text-4xl" aria-hidden="true"></i>
                            </div>
                            <h3 className="text-xl font-bold text-gray-600">No products found</h3>
                            <p className="text-gray-500">Try searching for generic terms like "Pain killer" or "Cough syrup"</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Quick View Modal */}
            {selectedProduct && (
                <div 
                    className="fixed inset-0 z-[100] flex items-center justify-center p-4 sm:p-6" 
                    role="dialog" 
                    aria-modal="true"
                    aria-labelledby="modal-title"
                >
                    <div 
                        className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity animate-fade-in" 
                        onClick={closeQuickView}
                    ></div>
                    <div className="relative bg-white rounded-3xl shadow-2xl max-w-5xl w-full max-h-[90vh] overflow-y-auto animate-popup-in flex flex-col md:flex-row overflow-hidden">
                         {/* Close Button */}
                         <button 
                            onClick={closeQuickView} 
                            className="absolute top-4 right-4 z-20 bg-white/80 hover:bg-white text-gray-500 hover:text-red-500 rounded-full w-10 h-10 flex items-center justify-center transition shadow-sm backdrop-blur-md"
                            aria-label="Close modal"
                         >
                            <i className="fas fa-times text-xl"></i>
                         </button>

                         {/* Left: Image & Call to Action */}
                         <div className="w-full md:w-2/5 bg-gray-50 flex flex-col">
                             <div className="flex-1 flex items-center justify-center p-8 relative">
                                <div className="absolute top-4 left-4">
                                    <span className="inline-block px-3 py-1 bg-white/80 backdrop-blur-sm text-gray-800 rounded-full text-xs font-bold tracking-wide shadow-sm">
                                        {isAiResult ? 'AI Suggested' : 'In Stock'}
                                    </span>
                                </div>
                                <img 
                                    src={selectedProduct.image} 
                                    alt={selectedProduct.name} 
                                    className="max-h-[300px] w-auto object-contain drop-shadow-xl transform transition hover:scale-105 duration-500" 
                                />
                             </div>
                             <div className="p-6 bg-white border-t border-gray-100 flex flex-col gap-4">
                                {/* Buttons Stack with consistent height/width */}
                                <a 
                                    href="https://wa.me/919798881368" 
                                    target="_blank" 
                                    rel="noopener noreferrer" 
                                    className="w-full bg-[#25D366] text-white font-bold py-3 px-6 rounded-xl hover:bg-[#20bd5a] transition shadow-lg flex items-center justify-center group hover:-translate-y-1"
                                >
                                    <i className="fab fa-whatsapp mr-2 text-xl"></i> Check Availability
                                </a>

                                <div className="w-full py-3 px-6 rounded-xl bg-red-50 text-red-600 border border-red-100 flex items-center justify-center font-bold text-sm tracking-wider shadow-sm">
                                    <i className="fas fa-store-alt mr-2"></i> Store Pickup Only
                                </div>
                             </div>
                         </div>

                         {/* Right: Details */}
                         <div className="w-full md:w-3/5 overflow-y-auto max-h-[90vh]">
                             <div className="p-8 md:p-10">
                                <span className="inline-block px-3 py-1 bg-medical-100 text-medical-700 rounded-full text-xs font-bold tracking-wide uppercase mb-4 w-fit">
                                    Pharmaceutical Product
                                </span>

                                {/* Header with Ask AI aligned to right */}
                                <div className="flex flex-col sm:flex-row justify-between items-start gap-4 mb-6">
                                    <div className="flex-1">
                                        <h2 id="modal-title" className="text-3xl font-bold text-gray-900 mb-2">{selectedProduct.name}</h2>
                                        <div className="w-16 h-1.5 bg-gradient-to-r from-medical-500 to-medical-300 rounded-full"></div>
                                    </div>

                                    {/* Transparent Touch Ask AI Button */}
                                    <button 
                                        onClick={(e) => askAI(selectedProduct, e)}
                                        className="flex-shrink-0 bg-white/50 border border-medical-200 hover:bg-medical-50 text-medical-700 px-4 py-2 rounded-lg transition-all duration-300 flex items-center shadow-sm hover:shadow-md font-semibold text-sm group"
                                    >
                                        <i className="fas fa-robot text-lg mr-2 text-medical-600 group-hover:rotate-12 transition-transform"></i>
                                        Ask AI
                                    </button>
                                </div>

                                <div className="space-y-6">
                                    <div>
                                        <h3 className="font-bold text-gray-900 mb-2 flex items-center">
