import { GoogleGenAI, Type } from "@google/genai";
import { Product } from "../types";

// Initialize safely - if API key is missing, it will throw only when called, not on app load
const getAIClient = () => {
    let apiKey = '';
    try {
        // Safe access to process.env for browser environments
        if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
            apiKey = process.env.API_KEY;
        }
    } catch (e) {
        console.warn("Could not access process.env");
    }

    if (!apiKey) {
        console.warn("API Key is missing.");
        return null;
    }
    return new GoogleGenAI({ apiKey });
};

const SYSTEM_INSTRUCTION = `You are a friendly AI Pharmacist assistant for 'New Lucky Pharma', a trusted medical store in Hanwara, Jharkhand.

RULES:
1. If the user starts with a simple greeting (e.g., "Hi", "Hello", "How are you?"), reply briefly with a friendly, single-sentence greeting and ask how you can help (e.g., "Hello! How can I assist you with your health questions today?").
2. MEDICAL/PRODUCT QUERIES:
   - Provide wellness tips and healthy living advice proactively.
   - Format your response strictly in a NUMBERED LIST (1., 2., 3.).
   - Each point must be on a new line.
   - Keep answers concise (max 5-10 lines total).
   - Ensure the format is clean and suitable for screenshots.
   - Do not write long paragraphs.
3. IMAGE ANALYSIS:
   - If the user provides an image (e.g., medicine, symptom, prescription), analyze it carefully.
   - If it's a medicine, identify it and explain its general use (always with a disclaimer).
   - If it's a symptom (like a rash), provide general information but emphasize seeing a doctor.
   - If the image is unclear, ask for a better photo.
4. MANDATORY DISCLAIMER: End every medical response with exactly: "Please consult a doctor for serious advice."
5. LOCATION: If asked, say: "We are located on Main Road, Hanwara (814154), open 7 days a week."

Example Format:
1. [Medicine Name/Tip]
2. [Usage/Benefit]
3. [When to take]
4. [Important Warning]
Please consult a doctor for serious advice.`;

// Helper to clean markdown bold syntax (**) from responses
const cleanText = (text: string): string => {
    if (!text) return "";
    // Remove ** markers but keep the text inside them
    return text.replace(/\*\*/g, '').trim();
};

export const getGeminiResponse = async (userMessage: string, imageBase64?: string): Promise<string> => {
    try {
        const ai = getAIClient();
        if (!ai) return "I am currently offline. Please check back later.";

        let contents: any = userMessage;

        // Handle Image Input
        if (imageBase64) {
             const match = imageBase64.match(/^data:([^;]+);base64,(.+)$/);
             if (match) {
                 const mimeType = match[1];
                 const data = match[2];
                 contents = {
                     parts: [
                         { inlineData: { mimeType, data } },
                         { text: userMessage || "Please analyze this image." }
                     ]
                 };
             }
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: contents,
            config: {
                systemInstruction: SYSTEM_INSTRUCTION,
            }
        });

        const text = response.text;
        return cleanText(text) || "I didn't quite catch that. Could you rephrase?";
    } catch (error) {
        console.error("Gemini API Error:", error);
        return "I'm having trouble connecting to the server. Please consult a pharmacist in person.";
    }
};

export const translateText = async (text: string): Promise<string> => {
    try {
        const ai = getAIClient();
        if (!ai) return text;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Translate the following medical advice into Hindi (or English if it is already in Hindi). Keep the numbered format and professional tone. Do not use bold markdown (**). Text to translate: \n\n${text}`,
        });

        return cleanText(response.text) || text;
    } catch (error) {
        console.error("Translation Error:", error);
        return text;
    }
};

export const searchProducts = async (query: string): Promise<Product[]> => {
    try {
        const ai = getAIClient();
        if (!ai) return [];

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Generate a list of 4 popular pharmaceutical products available in India related to '${query}'.`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.INTEGER },
                            name: { type: Type.STRING },
                            description: { type: Type.STRING },
                            imageKeyword: { type: Type.STRING, description: "A single keyword to search for an image, e.g., 'pill', 'syrup', 'bottle'" }
                        },
                        required: ["id", "name", "description", "imageKeyword"]
                    }
                }
            }
        });

        const rawData = response.text;
        if (!rawData) return [];

        const parsedData = JSON.parse(rawData);

        // Transform the AI response to match our Product type, adding placeholder images
        return parsedData.map((item: any, index: number) => ({
            id: Date.now() + index, // Unique ID
            name: item.name,
            description: item.description,
            // Use a reliable placeholder service with the name or keyword
            image: `https://placehold.co/600x400/e2e8f0/1e293b?text=${encodeURIComponent(item.name)}`,
            delay: `reveal-delay-${(index * 100) % 400}`
        }));

    } catch (error) {
        console.error("Gemini Search Error:", error);
        return [];
    }
};

import React, { useState, useRef, useEffect } from 'react';
import { getGeminiResponse, translateText } from '../services/geminiService';
import { ChatMessage } from '../types';

const AIChat: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false);

    // Lazy initialization for persistence
    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        try {
            const savedHistory = localStorage.getItem('chat_history');
            if (savedHistory) {
                return JSON.parse(savedHistory);
            }
        } catch (e) {
            console.error("Failed to parse chat history", e);
        }
        return [{
            id: 'welcome',
            text: "Hello! 👋 I'm your AI Pharmacist assistant. \n\nAsk me about: \n💊 Medicine uses \n🤒 Common symptoms \n🌿 Home remedies \n📷 Upload a photo of a medicine or prescription for help! \n\nNote: I am an AI, not a doctor. Please consult a professional for serious advice.",
            isUser: false,
            timestamp: Date.now()
        }];
    });

    const [inputValue, setInputValue] = useState('');
    const [selectedImage, setSelectedImage] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    // UI States for actions
    const [copiedId, setCopiedId] = useState<string | null>(null);
    const [translatingId, setTranslatingId] = useState<string | null>(null);

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Save history to local storage whenever messages change
    useEffect(() => {
        if (messages.length > 0) {
            localStorage.setItem('chat_history', JSON.stringify(messages));
        }
    }, [messages]);

    // Listen for 'ask-ai' custom events from other components
    useEffect(() => {
        const handleAskAI = (e: any) => {
            const { productName, description } = e.detail;
            const query = `Can you explain what ${productName} is used for and provide some health tips? \n\nDescription context: ${description}`;

            setIsOpen(true);

            // Trigger the AI request
            handleExternalQuery(query);
        };

        window.addEventListener('ask-ai', handleAskAI);
        return () => window.removeEventListener('ask-ai', handleAskAI);
    }, []);

    const toggleChat = () => setIsOpen(!isOpen);

    const clearHistory = () => {
        if (window.confirm("Are you sure you want to clear your chat history?")) {
            const defaultMessage = {
                id: 'welcome',
                text: "Hello! 👋 I'm your AI Pharmacist assistant. \n\nAsk me about: \n💊 Medicine uses \n🤒 Common symptoms \n🌿 Home remedies \n📷 Upload a photo of a medicine or prescription for help! \n\nNote: I am an AI, not a doctor. Please consult a professional for serious advice.",
                isUser: false,
                timestamp: Date.now()
            };
            setMessages([defaultMessage]);
            localStorage.removeItem('chat_history');
        }
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages, isOpen]);

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onloadend = () => {
                setSelectedImage(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    const removeImage = () => {
        setSelectedImage(null);
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const handleCopy = async (id: string, text: string) => {
        try {
            await navigator.clipboard.writeText(text);
            setCopiedId(id);
            setTimeout(() => setCopiedId(null), 2000);
        } catch (err) {
            console.error('Failed to copy text: ', err);
        }
    };

    const handleTranslate = async (id: string, text: string) => {
        setTranslatingId(id);
        const translatedText = await translateText(text);

        setMessages(prev => prev.map(msg => 
            msg.id === id ? { ...msg, text: translatedText } : msg
        ));
        setTranslatingId(null);
    };

    const handleExternalQuery = async (text: string) => {
        const newMessage: ChatMessage = {
            id: Date.now().toString(),
            text: text,
            isUser: true,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, newMessage]);
        setIsLoading(true);

        const aiResponseText = await getGeminiResponse(text);

        const aiMessage: ChatMessage = {
            id: (Date.now() + 1).toString(),
            text: aiResponseText,
            isUser: false,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, aiMessage]);
        setIsLoading(false);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!inputValue.trim() && !selectedImage) return;

        const userText = inputValue.trim();
        const userImage = selectedImage;

        const newMessage: ChatMessage = {
            id: Date.now().toString(),
            text: userText,
            image: userImage || undefined,
            isUser: true,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, newMessage]);
        setInputValue('');
        setSelectedImage(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
        setIsLoading(true);

        const aiResponseText = await getGeminiResponse(userText, userImage || undefined);

        const aiMessage: ChatMessage = {
            id: (Date.now() + 1).toString(),
            text: aiResponseText,
            isUser: false,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, aiMessage]);
        setIsLoading(false);
    };

    return (
        <>
            {/* FAB */}
            <button 
                onClick={toggleChat}
                className="fixed bottom-6 right-6 z-[90] bg-gradient-to-r from-medical-600 to-medical-500 hover:from-medical-700 hover:to-medical-600 text-white p-4 rounded-full shadow-2xl transition transform hover:scale-110 group animate-pulse"
            >
                <span className="absolute -top-1 -right-1 flex h-4 w-4">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-yellow-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-4 w-4 bg-yellow-500"></span>
                </span>
                <i className={`fas ${isOpen ? 'fa-times' : 'fa-robot'} text-2xl group-hover:rotate-12 transition duration-300`}></i>
                <span className="absolute right-full mr-3 top-1/2 -translate-y-1/2 bg-gray-900 text-white px-3 py-1 rounded-lg text-sm font-bold whitespace-nowrap opacity-0 group-hover:opacity-100 transition duration-300 pointer-events-none shadow-lg">
                    ✨ AI Pharmacist
                </span>
            </button>

            {/* Modal */}
            <div 
                className={`fixed inset-0 z-[100] flex items-end sm:items-center justify-center px-0 sm:px-4 backdrop-blur-sm bg-black/50 transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
                onClick={(e) => e.target === e.currentTarget && toggleChat()}
            >
                <div 
                    className={`bg-white w-full sm:max-w-md h-[85vh] sm:h-[600px] sm:rounded-3xl rounded-t-3xl shadow-2xl flex flex-col transform transition-transform duration-300 ${isOpen ? 'translate-y-0 scale-100' : 'translate-y-full sm:translate-y-0 scale-95'}`}
                >
                    {/* Header */}
                    <div className="bg-gradient-to-r from-medical-600 to-medical-500 p-4 flex items-center justify-between sm:rounded-t-3xl rounded-t-3xl">
                        <div className="flex items-center gap-3">
                            <div className="bg-white/20 p-2 rounded-full backdrop-blur-sm">
                                <i className="fas fa-robot text-white text-xl"></i>
                            </div>
                            <div>
                                <h3 className="text-white font-bold text-lg">AI Pharmacist ✨</h3>
                                <p className="text-medical-100 text-xs flex items-center">
                                    <span className="w-2 h-2 bg-green-400 rounded-full mr-1 animate-pulse"></span> Online
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <button 
                                onClick={clearHistory}
                                className="text-white/80 hover:text-white hover:bg-white/10 p-2 rounded-full transition"
                                title="Clear History"
                            >
                                <i className="fas fa-trash-alt text-sm"></i>
                            </button>
                            <button onClick={toggleChat} className="text-white/80 hover:text-white transition p-2 hover:bg-white/10 rounded-full">
                                <i className="fas fa-times text-xl"></i>
                            </button>
                        </div>
                    </div>

                    {/* Chat Area */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 scroll-smooth">
                        {messages.map((msg, index) => {
                            // Date Separator Logic
                            const showDate = index === 0 || 
                                new Date(msg.timestamp).toLocaleDateString() !== new Date(messages[index - 1].timestamp).toLocaleDateString();

                            const dateLabel = new Date(msg.timestamp).toLocaleDateString() === new Date().toLocaleDateString() 
                                ? 'Today' 
                                : new Date(msg.timestamp).toLocaleDateString();

                            return (
                                <React.Fragment key={msg.id}>
                                    {showDate && (
                                        <div className="flex justify-center my-4 animate-fade-in">
                                            <span className="bg-gray-200/80 backdrop-blur-sm text-gray-500 text-[10px] font-bold uppercase tracking-wider py-1 px-3 rounded-full shadow-sm">
                                                {dateLabel}
                                            </span>
                                        </div>
                                    )}
                                    <div className={`flex items-start gap-3 animate-slide-up ${msg.isUser ? 'flex-row-reverse' : ''}`}>
                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.isUser ? 'bg-gray-200' : 'bg-medical-100'}`}>
                                            <i className={`fas ${msg.isUser ? 'fa-user text-gray-600' : 'fa-robot text-medical-600'} text-sm`}></i>
                                        </div>
                                        <div className={`flex flex-col ${msg.isUser ? 'items-end' : 'items-start'} max-w-[80%]`}>
                                            <div className={`${msg.isUser ? 'bg-medical-600 text-white rounded-tr-none' : 'bg-white text-gray-700 rounded-tl-none border border-gray-100'} p-3 rounded-2xl shadow-sm text-sm whitespace-pre-wrap`}>
                                                {msg.image && (
                                                    <img 
                                                        src={msg.image} 
                                                        alt="User upload" 
                                                        className="rounded-lg mb-2 max-h-48 object-cover border border-white/20"
                                                    />
                                                )}
                                                {msg.text}
                                            </div>

                                            {/* AI Message Actions (Copy & Translate) */}
                                            {!msg.isUser && (
                                                <div className="flex items-center gap-2 mt-1 px-1">
                                                    <button 
                                                        onClick={() => handleCopy(msg.id, msg.text)}
                                                        className="text-gray-400 hover:text-medical-600 transition flex items-center gap-1 bg-white/50 px-2 py-1 rounded-md shadow-sm border border-transparent hover:border-gray-200"
                                                        title="Copy Text"
                                                    >
                                                        {copiedId === msg.id ? (
                                                            <><i className="fas fa-check text-green-500 text-xs"></i><span className="text-[10px] font-medium text-green-600">Copied</span></>
                                                        ) : (
                                                            <><i className="far fa-copy text-xs"></i><span className="text-[10px]">Copy</span></>
                                                        )}
                                                    </button>
                                                    <button 
                                                        onClick={() => handleTranslate(msg.id, msg.text)}
                                                        disabled={translatingId === msg.id}
                                                        className="text-gray-400 hover:text-blue-600 transition flex items-center gap-1 bg-white/50 px-2 py-1 rounded-md shadow-sm border border-transparent hover:border-gray-200 disabled:opacity-50"
